dashboard.definition:
{
  "title": "Source - Exchange",
  "description": "Exchange Online message trace — email flow, delivery health, and phishing detection",
  "dataSources": {
    "ds_total_events": {
      "type": "ds.search",
      "name": "Total Exchange Events Over Time",
      "options": {
        "query": "| tstats count where index=fake_tshrt sourcetype=\"FAKE:o365:reporting:messagetrace\" by _time span=1h"
      }
    },
    "ds_delivery_failures": {
      "type": "ds.search",
      "name": "Delivery Failures",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:o365:reporting:messagetrace\" Status!=\"Delivered\" Status=* | stats count"
      }
    },
    "ds_unique_senders": {
      "type": "ds.search",
      "name": "Unique Senders",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:o365:reporting:messagetrace\" SenderAddress=* | stats dc(SenderAddress) as count"
      }
    },
    "ds_unique_recipients": {
      "type": "ds.search",
      "name": "Unique Recipients",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:o365:reporting:messagetrace\" RecipientAddress=* | stats dc(RecipientAddress) as count"
      }
    },
    "ds_events_over_time": {
      "type": "ds.search",
      "name": "Message Flow Over Time",
      "options": {
        "query": "| tstats count where index=fake_tshrt sourcetype=\"FAKE:o365:reporting:messagetrace\" by _time span=1h"
      }
    },
    "ds_status_breakdown": {
      "type": "ds.search",
      "name": "Delivery Status",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:o365:reporting:messagetrace\" Status=* | stats count by Status | sort -count"
      }
    },
    "ds_top_senders": {
      "type": "ds.search",
      "name": "Top Senders by Volume",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:o365:reporting:messagetrace\" SenderAddress=* | stats count by SenderAddress | sort -count | head 15 | rename SenderAddress as \"Sender\""
      }
    },
    "ds_recent_failures": {
      "type": "ds.search",
      "name": "Recent Delivery Failures",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:o365:reporting:messagetrace\" Status!=\"Delivered\" | table _time SenderAddress RecipientAddress Subject Status | sort -_time | head 30 | rename SenderAddress as \"Sender\" RecipientAddress as \"Recipient\""
      }
    }
  },
  "visualizations": {
    "viz_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "# Source — Exchange\n\n**Sourcetype:** `FAKE:o365:reporting:messagetrace` | **Coverage:** Exchange Online message trace for all email flow | **Format:** CSV\n\n**Why monitor?** Track email delivery health, detect phishing attempts reaching inboxes, and ensure business communication flows without disruption.",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_kpi_total_events": {
      "type": "splunk.singlevalue",
      "title": "Total Messages",
      "dataSources": { "primary": "ds_total_events" },
      "options": {
        "majorValue": "> sparklineValues | lastPoint()",
        "sparklineValues": "> primary | seriesByName('count')",
        "sparklineDisplay": "below",
        "majorColor": "#00D2FF",
        "backgroundColor": "transparent",
        "showSparklineAreaGraph": true,
        "sparklineStrokeColor": "#00D2FF"
      }
    },
    "viz_kpi_delivery_failures": {
      "type": "splunk.singlevalue",
      "title": "Delivery Failures",
      "dataSources": { "primary": "ds_delivery_failures" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#DC4E41",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_unique_senders": {
      "type": "splunk.singlevalue",
      "title": "Unique Senders",
      "dataSources": { "primary": "ds_unique_senders" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#7B56DB",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_unique_recipients": {
      "type": "splunk.singlevalue",
      "title": "Unique Recipients",
      "dataSources": { "primary": "ds_unique_recipients" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#53A051",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_events_over_time": {
      "type": "splunk.area",
      "title": "Message Flow Over Time",
      "dataSources": { "primary": "ds_events_over_time" },
      "options": {
        "stackMode": "stacked",
        "legendDisplay": "off",
        "nullValueDisplay": "zero",
        "areaOpacity": 0.7,
        "backgroundColor": "transparent",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "Messages / hour",
        "yAxisTitleVisibility": "show",
        "yAxisAbbreviation": "auto",
        "seriesColors": ["#00D2FF"]
      },
      "showProgressBar": true,
      "showLastUpdated": true
    },
    "viz_status_breakdown": {
      "type": "splunk.pie",
      "title": "Delivery Status",
      "dataSources": { "primary": "ds_status_breakdown" },
      "options": {
        "labelDisplay": "valuesAndPercentage",
        "showDonutHole": true,
        "seriesColors": ["#53A051", "#DC4E41", "#F8BE34", "#7B56DB", "#00D2FF", "#009CEB", "#F1813F", "#00CDAF"]
      }
    },
    "viz_top_senders": {
      "type": "splunk.bar",
      "title": "Top Senders by Volume",
      "dataSources": { "primary": "ds_top_senders" },
      "options": {
        "seriesColors": ["#7B56DB"],
        "legendDisplay": "off",
        "xAxisTitleText": "Messages Sent",
        "xAxisTitleVisibility": "show",
        "yAxisTitleVisibility": "hide",
        "backgroundColor": "transparent"
      },
      "showProgressBar": true
    },
    "viz_failures_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "### Recent Delivery Failures",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_recent_failures": {
      "type": "splunk.table",
      "title": "Recent Delivery Failures",
      "dataSources": { "primary": "ds_recent_failures" },
      "options": {
        "count": 20,
        "showRowNumbers": false
      },
      "showProgressBar": true,
      "showLastUpdated": true
    }
  },
  "inputs": {
    "input_global_trp": {
      "type": "input.timerange",
      "title": "Time Range",
      "options": {
        "token": "global_time",
        "defaultValue": "1767225600,1769904000"
      }
    }
  },
  "defaults": {
    "dataSources": {
      "ds.search": {
        "options": {
          "queryParameters": {
            "earliest": "$global_time.earliest$",
            "latest": "$global_time.latest$"
          }
        }
      }
    }
  },
  "layout": {
    "type": "grid",
    "globalInputs": ["input_global_trp"],
    "structure": [
      { "item": "viz_header", "type": "block", "position": { "x": 0, "y": 0, "w": 1200, "h": 150 } },
      { "item": "viz_kpi_total_events", "type": "block", "position": { "x": 0, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_kpi_delivery_failures", "type": "block", "position": { "x": 300, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_kpi_unique_senders", "type": "block", "position": { "x": 600, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_kpi_unique_recipients", "type": "block", "position": { "x": 900, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_events_over_time", "type": "block", "position": { "x": 0, "y": 270, "w": 750, "h": 350 } },
      { "item": "viz_status_breakdown", "type": "block", "position": { "x": 750, "y": 270, "w": 450, "h": 350 } },
      { "item": "viz_top_senders", "type": "block", "position": { "x": 0, "y": 620, "w": 1200, "h": 300 } },
      { "item": "viz_failures_header", "type": "block", "position": { "x": 0, "y": 920, "w": 1200, "h": 50 } },
      { "item": "viz_recent_failures", "type": "block", "position": { "x": 0, "y": 970, "w": 1200, "h": 400 } }
    ]
  }
}
